38	function findValidSession(): Session | null {
39	  try {
40	    for (let i = 0; i < localStorage.length; i++) {
41	      const key = localStorage.key(i);
42	      if (key && /^session_/.test(key)) {
43	        const raw = localStorage.getItem(key);
44	        if (raw) {
45	          const parsed: Session = JSON.parse(raw);
46	          if (parsed.expires_at > Date.now()) {
47	            return parsed;
48	          }
49	        }
50	      }
51	    }
52	  } catch {
53	    // localStorage may be unavailable (SSR, security restrictions, etc.)
54	  }
55	  return null;
56	}
57	
58	export const authStore = writable<Session | null>(null);
59	
60	export function initAuthStore(): void {
61	  const session = findValidSession();
62	  authStore.set(session);
63	}
