84	// 2. logout
85	// ============================================================
86	
87	async function logout(): Promise<void> {
88	  const session = get(authStore);
89	
90	  if (session) {
91	    localStorage.removeItem(`session_${session.user_id}`);
92	    channelManager.broadcast(CHANNELS.AUTH_SYNC, {
93	      type: 'logout',
94	      user_id: session.user_id,
95	    });
96	  }
97	
98	  authStore.set(null);
99	}
