128	// ============================================================
129	// 4. changePassword
130	// ============================================================
131	
132	async function changePassword(
133	  userId: string,
134	  oldPassword: string,
135	  newPassword: string
136	): Promise<void> {
137	  const user: User | undefined = await idbAccessLayer.get('users', userId);
138	  if (!user) {
139	    throw new Error('User not found');
140	  }
141	
142	  // Verify old password
143	  const oldHash = await encryptionService.hashPassword(
144	    oldPassword,
145	    new Uint8Array(user.salt) as unknown as Uint8Array
146	  );
147	
148	  if (!compareBuffers(oldHash, user.password_hash)) {
149	    throw new Error('Current password is incorrect');
150	  }
151	
152	  // Generate new credentials
153	  const newSalt = encryptionService.generateSalt();
154	  const newHash = await encryptionService.hashPassword(newPassword, newSalt);
155	
156	  // Re-encrypt if encryption is enabled
157	  if (user.encryption_enabled) {
158	    await encryptionService.reEncryptAll(
159	      userId,
160	      oldPassword,
161	      newPassword,
162	      async () => {
163	        // Gather all encrypted records for this user — include user record itself
164	        const allStores = ['users'];
165	        const records: Array<{ store: string; record: Record<string, unknown> }> = [];
166	        const currentUser = await idbAccessLayer.get('users', userId);
167	        if (currentUser) {
168	          records.push({ store: 'users', record: currentUser as unknown as Record<string, unknown> });
169	        }
170	        return records;
171	      },
172	      async (records) => {
173	        for (const { store, record } of records) {
174	          await idbAccessLayer.put(store, record);
175	        }
176	      }
177	    );
178	  }
179	
180	  // Update user record
181	  const updatedUser: User = {
182	    ...user,
183	    password_hash: newHash,
184	    salt: newSalt.buffer as ArrayBuffer,
185	    _version: user._version + 1,
186	  };
187	  await idbAccessLayer.put('users', updatedUser);
188	
189	  // Broadcast session refresh
190	  channelManager.broadcast(CHANNELS.AUTH_SYNC, {
191	    type: 'session-refresh',
192	    user_id: userId,
193	  });
194	}
