15	// ============================================================
16	// App Initialization Sequence
17	// ============================================================
18	
19	export async function initializeApp(
20	  onProgress?: (message: string) => void,
21	): Promise<Session | null> {
22	  // 1. Initialize IndexedDB
23	  onProgress?.('Initializing database...');
24	  await idbAccessLayer.init();
25	
26	  // 2. Load default configuration
27	  onProgress?.('Loading configuration...');
28	  await opsConfigService.loadDefaults();
29	
30	  // 3. Seed rooms if empty
31	  onProgress?.('Checking room data...');
32	  const existingRooms = await idbAccessLayer.getAll('rooms');
33	  if (existingRooms.length === 0) {
34	    for (const room of roomsJson) {
35	      await idbAccessLayer.put('rooms', { ...room, _version: 1 });
36	    }
37	  }
38	
39	  // 4. Seed default admin user if no users exist
40	  onProgress?.('Checking user data...');
41	  const existingUsers = await idbAccessLayer.getAll('users');
42	  if (existingUsers.length === 0) {
43	    await authService.createUser({
44	      username: 'admin',
45	      password: 'admin',
46	      role: 'SYSTEM_ADMIN' as Role,
47	      org_unit: 'system',
48	    });
49	  }
50	
51	  // 5. Seed sessions if empty
52	  onProgress?.('Checking session data...');
53	  const existingSessions = await idbAccessLayer.getAll('sessions');
54	  if (existingSessions.length === 0) {
55	    const now = Date.now();
56	    const DAY = 86_400_000;
57	    for (let i = 0; i < sessionsJson.length; i++) {
58	      const s = sessionsJson[i];
59	      // Spread sessions across the next 7 days, 2-hour blocks starting at 9 AM
60	      const dayOffset = (i % 7) + 1;
61	      const startOfDay = new Date(now + dayOffset * DAY);
62	      startOfDay.setHours(9 + (i % 3) * 2, 0, 0, 0);
63	      const startTime = startOfDay.getTime();
64	      const endTime = startTime + 2 * 60 * 60 * 1000; // 2 hours
65	
66	      await idbAccessLayer.put('sessions', {
67	        ...s,
68	        start_time: startTime,
69	        end_time: endTime,
70	        _version: 1,
71	      });
72	    }
73	  }
74	
75	  // 6. Restore session
76	  onProgress?.('Restoring session...');
77	  const session = authService.restoreSession();
78	
79	  // 7. Initialize feature flags
80	  onProgress?.('Loading feature flags...');
81	  if (session) {
82	    await featureFlagService.initialize({ role: session.role, org_unit: session.org_unit });
83	  } else {
84	    await featureFlagService.initialize();
85	  }
86	
87	  // 8. Initialize cross-tab sync
88	  authService.initCrossTabSync();
89	  registrationService.initCrossTabSync();
90	
91	  // 9. Initialize scheduler and register recurring tasks
92	  onProgress?.('Initializing scheduler...');
93	  await schedulerService.initialize(onProgress);
94	
95	  // Register billing task: 1st of month at 12:05 AM
96	  await schedulerService.registerTask({
97	    task_id: 'monthly-billing',
98	    schedule_definition: 'monthly:1:0:05',
99	    task_type: 'billing',
100	    handler: async () => {
101	      await billingService.generateMonthlyBills();
102	    },
103	  });
104	
105	  // Register overdue bill check: daily
106	  await schedulerService.registerTask({
107	    task_id: 'overdue-check',
108	    schedule_definition: 'interval:24',
109	    task_type: 'billing',
110	    handler: async () => {
111	      await billingService.markOverdueBills();
112	    },
113	  });
114	
115	  // Register reminder delivery check: every hour
116	  await schedulerService.registerTask({
117	    task_id: 'reminder-delivery',
118	    schedule_definition: 'interval:1',
119	    task_type: 'reminder',
120	    handler: async () => {
121	      await todoReminderService.deliverPending();
122	      await todoReminderService.deliverQueuedBatch();
123	    },
124	  });
125	
126	  // Register idempotency key cleanup: every 6 hours
127	  await schedulerService.registerTask({
128	    task_id: 'idempotency-cleanup',
129	    schedule_definition: 'interval:6',
130	    task_type: 'cleanup',
131	    handler: async () => {
132	      await idempotencyService.cleanup();
133	    },
134	  });
135	
136	  // 10. Run consistency check (non-blocking)
137	  runConsistencyCheckAsync();
138	
139	  onProgress?.('');
140	  return session;
141	}
142	
143	async function runConsistencyCheckAsync(): Promise<void> {
144	  try {
145	    const { runConsistencyCheck } = await import('../utils/consistencyChecker');
146	    const report = await runConsistencyCheck();
147	    if (report.issues.length > 0) {
148	      console.warn(`Consistency check found ${report.issues.length} issue(s):`, report.issues);
149	    }
150	  } catch (err) {
151	    console.warn('Consistency check failed:', err);
152	  }
153	}
