47	function evaluateFlag(flagId: string, context: { role: string; org_unit: string }): boolean {
48	  const flag = cache.get(flagId);
49	  if (!flag) return false;
50	
51	  if (!flag.enabled) return false;
52	
53	  if (flag.target_roles.length > 0 && !flag.target_roles.includes(context.role as Role)) {
54	    return false;
55	  }
56	
57	  if (flag.target_org_units.length > 0 && !flag.target_org_units.includes(context.org_unit)) {
58	    return false;
59	  }
60	
61	  return true;
62	}
