197	async function swap(
198	  participantId: string,
199	  fromSessionId: string,
200	  toSessionId: string,
201	  idempotencyKey: string,
202	): Promise<Registration> {
203	  // 1. RBAC
204	  rbacService.checkPermission('registration:manage');
205	
206	  // 2. Idempotency
207	  const idempCheck = await idempotencyService.checkKey(idempotencyKey);
208	  if (idempCheck.isDuplicate) {
209	    return idempCheck.cachedResult as Registration;
210	  }
211	
212	  // 3. Rate limit
213	  await checkRateLimit(participantId);
214	
215	  // 4. Blacklist check for target session
216	  const isBlacklisted = await opsConfigService.isBlacklisted('participant', participantId);
217	  if (isBlacklisted) {
218	    throw new Error('Registration denied: participant is restricted.');
219	  }
220	
221	  // 5. SINGLE atomic transaction: drop from old + add to new
222	  const newRegistration = await idbAccessLayer.transaction<Registration>(
223	    ['sessions', 'registrations'],
224	    'readwrite',
225	    async (tx) => {
226	      // --- DROP from old session ---
227	      const oldRegs = await tx.getAll<Registration>('registrations', 'idx_session', fromSessionId);
228	      const activeReg = oldRegs.find(
229	        (r) => r.participant_id === participantId && r.status === 'active'
230	      );
231	      if (!activeReg) {
232	        throw new Error('No active registration found in the source session.');
233	      }
234	
235	      // Cancel old registration
236	      await tx.put('registrations', {
237	        ...activeReg,
238	        status: 'swapped',
239	        _version: activeReg._version + 1,
240	      });
241	
242	      // Increment old session capacity
243	      const oldSession = await tx.get<SessionRecord>('sessions', fromSessionId);
244	      if (!oldSession) throw new Error(`Source session ${fromSessionId} not found`);
245	      await tx.put('sessions', {
246	        ...oldSession,
247	        current_enrollment: Math.max(0, oldSession.current_enrollment - 1),
248	        _version: oldSession._version + 1,
249	      });
250	
251	      // --- ADD to new session ---
252	      const newSession = await tx.get<SessionRecord>('sessions', toSessionId);
253	      if (!newSession) throw new Error(`Target session ${toSessionId} not found`);
254	      if (newSession.status === 'cancelled') throw new Error('Target session is cancelled.');
255	
256	      const newAvailable = newSession.capacity - newSession.current_enrollment;
257	      if (newAvailable <= 0) {
258	        throw new Error(
259	          'The swap could not be completed. Target session is full. ' +
260	          'Your original registration has been preserved.'
261	        );
262	      }
263	
264	      // Check no existing active registration in target
265	      const newRegs = await tx.getAll<Registration>('registrations', 'idx_session', toSessionId);
266	      const existingInTarget = newRegs.find(
267	        (r) => r.participant_id === participantId && r.status === 'active'
268	      );
269	      if (existingInTarget) {
270	        throw new Error('You already have an active registration in the target session.');
271	      }
272	
273	      // Decrement new session capacity
274	      await tx.put('sessions', {
275	        ...newSession,
276	        current_enrollment: newSession.current_enrollment + 1,
277	        _version: newSession._version + 1,
278	      });
279	
280	      // Create new registration
281	      const reg: Registration = {
282	        registration_id: crypto.randomUUID(),
283	        participant_id: participantId,
284	        session_id: toSessionId,
285	        status: 'active',
286	        registered_at: Date.now(),
287	        _version: 1,
288	      };
289	      await tx.put('registrations', reg);
290	
291	      return reg;
292	    }
293	  );
294	
295	  // Mark idempotency complete
296	  await idempotencyService.markComplete(idempotencyKey, newRegistration);
297	
298	  // Broadcast capacity changes for both sessions
299	  const fromSession = await idbAccessLayer.get<SessionRecord>('sessions', fromSessionId);
300	  const toSession = await idbAccessLayer.get<SessionRecord>('sessions', toSessionId);

1	import { idbAccessLayer } from './idbAccessLayer';
