155	async function markOverdueBills(): Promise<void> {
156	  const allBills = await idbAccessLayer.getAll<Bill>('bills');
157	  const now = Date.now();
158	
159	  for (const bill of allBills) {
160	    if (bill.status === 'generated' && now > bill.due_date) {
161	      await idbAccessLayer.put('bills', {
162	        ...bill,
163	        status: 'overdue',
164	        _version: bill._version + 1,
165	      } as any);
166	    }
167	  }
168	}
