55	function isDndActive(): boolean {
56	  try {
57	    const config = localStorage.getItem('dnd_config');
58	    const { start, end } = config ? JSON.parse(config) : { start: '22:00', end: '07:00' };
59	    const now = new Date();
60	    const currentMinutes = now.getHours() * 60 + now.getMinutes();
61	    const [startH, startM] = start.split(':').map(Number);
62	    const [endH, endM] = end.split(':').map(Number);
63	    const startMinutes = startH * 60 + startM;
64	    const endMinutes = endH * 60 + endM;
65	
66	    if (startMinutes > endMinutes) {
67	      // Overnight window (e.g., 22:00 - 07:00)
68	      return currentMinutes >= startMinutes || currentMinutes < endMinutes;
69	    }
70	    return currentMinutes >= startMinutes && currentMinutes < endMinutes;
71	  } catch {
72	    return false;
73	  }
74	}
75	
76	function getDndEndTime(): number {
77	  try {
78	    const config = localStorage.getItem('dnd_config');
79	    const { end } = config ? JSON.parse(config) : { end: '07:00' };
80	    const [endH, endM] = end.split(':').map(Number);
81	    const now = new Date();
82	    const dndEnd = new Date(now);
83	    dndEnd.setHours(endH, endM, 0, 0);
84	
85	    // If DND end is earlier today, it means tomorrow
86	    if (dndEnd.getTime() <= now.getTime()) {
87	      dndEnd.setDate(dndEnd.getDate() + 1);
88	    }
89	    return dndEnd.getTime();
90	  } catch {
91	    // Default: 7 AM tomorrow
92	    const tomorrow = new Date();
93	    tomorrow.setDate(tomorrow.getDate() + 1);
94	    tomorrow.setHours(7, 0, 0, 0);
95	    return tomorrow.getTime();
96	  }
97	}
