99	// ============================================================
100	// Cron-like Schedule Parsing
101	// ============================================================
102	
103	function computeNextRun(scheduleDefinition: string, afterTimestamp?: number): number {
104	  const after = afterTimestamp || Date.now();
105	
106	  // Simple schedule formats:
107	  // "monthly:1:00:05" = 1st of month at 00:05
108	  // "interval:HOURS" = every N hours from now
109	  // "once:TIMESTAMP" = one-shot at specific time
110	
111	  if (scheduleDefinition.startsWith('monthly:')) {
112	    const parts = scheduleDefinition.split(':');
113	    const day = parseInt(parts[1], 10);
114	    const hour = parseInt(parts[2], 10);
115	    const minute = parseInt(parts[3], 10);
116	
117	    const next = new Date(after);
118	    next.setDate(day);
119	    next.setHours(hour, minute, 0, 0);
120	
121	    // If this month's run has passed, go to next month
122	    if (next.getTime() <= after) {
123	      next.setMonth(next.getMonth() + 1);
124	    }
125	    return next.getTime();
126	  }
127	
128	  if (scheduleDefinition.startsWith('interval:')) {
129	    const hours = parseInt(scheduleDefinition.split(':')[1], 10);
130	    return after + hours * 60 * 60 * 1000;
131	  }
132	
133	  if (scheduleDefinition.startsWith('once:')) {
134	    return parseInt(scheduleDefinition.split(':')[1], 10);
135	  }
136	
137	  // Default: 24 hours from now
138	  return after + 24 * 60 * 60 * 1000;
139	}
140	
141	function countMissedPeriods(scheduleDefinition: string, nextRunAt: number): number {
142	  if (!scheduleDefinition.startsWith('monthly:')) return 1;
143	
144	  let count = 0;
145	  let cursor = nextRunAt;
146	  const now = Date.now();
147	
148	  while (cursor < now) {
149	    count++;
150	    cursor = computeNextRun(scheduleDefinition, cursor);
151	  }
152	
153	  return Math.max(count, 1);
154	}
