156	// ============================================================
157	// Task Execution
158	// ============================================================
159	
160	async function executeTask(task: SchedulerTask): Promise<void> {
161	  const handler = taskHandlers.get(task.task_id);
162	  if (!handler) {
163	    console.warn(`No handler registered for task ${task.task_id}`);
164	    return;
165	  }
166	
167	  // For reminder tasks, check DND
168	  if (task.task_type === 'reminder' && isDndActive()) {
169	    const dndEnd = getDndEndTime();
170	    // Recompute fire_at to DND end time
171	    task.next_run_at = dndEnd;
172	    await persistNextRunAt(task.task_id, dndEnd);
173	    return;
174	  }
175	
176	  // Mark as executing in IndexedDB (prevents duplicate execution from other tabs)
177	  const current = await idbAccessLayer.get<SchedulerTask>('scheduler_tasks', task.task_id);
178	  if (!current || current.status === 'executing') return; // Another tab got it
179	
180	  await idbAccessLayer.put('scheduler_tasks', {
181	    ...current,
182	    status: 'executing',
183	    _version: current._version,
184	  });
185	
186	  try {
187	    await handler();
188	
189	    // Success: advance next_run_at
190	    const nextRun = task.schedule_definition.startsWith('once:')
191	      ? 0
192	      : computeNextRun(task.schedule_definition);
193	
194	    const updated: Partial<SchedulerTask> & { task_id: string; _version: number } = {
195	      ...current,
196	      status: task.schedule_definition.startsWith('once:') ? 'completed' as const : 'active' as const,
197	      consecutive_failures: 0,
198	      last_error: null,
199	      next_run_at: nextRun,
200	      _version: current._version + 1,
201	    };
202	
203	    await idbAccessLayer.put('scheduler_tasks', updated);
204	    await persistNextRunAt(task.task_id, nextRun);
205	
206	    // Broadcast to other tabs
207	    channelManager.broadcast(CHANNELS.SCHEDULER_SYNC, {
208	      type: 'task-executed',
209	      task_id: task.task_id,
210	      tab_id: tabId,
211	      new_next_run_at: nextRun,
212	    } as SchedulerSyncMessage);
213	  } catch (err: any) {
214	    // Failure: log error, schedule retry
215	    const errorMessage = err?.message || String(err);
216	
217	    // Log to error_logs
218	    await idbAccessLayer.put('error_logs', {
219	      log_id: crypto.randomUUID(),
220	      task_id: task.task_id,
221	      error_message: errorMessage,
222	      stack_trace: err?.stack || null,
223	      timestamp: Date.now(),
224	    });
225	
226	    const failures = (current.consecutive_failures || 0) + 1;
227	
228	    if (failures >= MAX_RETRIES) {
229	      // Mark as permanently failed
230	      await idbAccessLayer.put('scheduler_tasks', {
231	        ...current,
232	        status: 'failed' as const,
233	        consecutive_failures: failures,
234	        last_error: errorMessage,
235	        _version: current._version + 1,
236	      });
237	
238	      // Notify admins (will be wired to messageCenterService in Phase 4)
239	      console.error(`Task ${task.task_id} permanently failed after ${MAX_RETRIES} retries: ${errorMessage}`);
240	    } else {
241	      // Schedule retry with exponential backoff
242	      const delay = Math.min(INITIAL_RETRY_MS * Math.pow(2, failures - 1), MAX_RETRY_MS);
243	      const retryAt = Date.now() + delay;
244	
245	      await idbAccessLayer.put('scheduler_tasks', {
246	        ...current,
247	        status: 'active' as const,
248	        consecutive_failures: failures,
249	        last_error: errorMessage,
250	        next_run_at: retryAt,
251	        _version: current._version + 1,
252	      });
253	      await persistNextRunAt(task.task_id, retryAt);
254	
255	      // Set local retry timer
256	      const timer = setTimeout(() => checkAndExecuteTask(task.task_id), delay);
257	      retryTimers.set(task.task_id, timer);
258	    }
259	  }
260	}
261	
262	// ============================================================
263	// Persistence Helpers
264	// ============================================================
265	
266	function persistNextRunAt(taskId: string, nextRunAt: number): Promise<void> {
267	  try {
268	    localStorage.setItem(`scheduler_next_run_${taskId}`, String(nextRunAt));
269	  } catch {
270	    // LocalStorage full — degrade gracefully
271	    console.warn('LocalStorage full, scheduler next_run_at not persisted');
272	  }
273	  return Promise.resolve();
274	}
275	
276	function readNextRunAt(taskId: string): number | null {
277	  try {
278	    const val = localStorage.getItem(`scheduler_next_run_${taskId}`);
279	    return val ? parseInt(val, 10) : null;
280	  } catch {
281	    return null;
282	  }
283	}
284	
285	// ============================================================
286	// Polling & Execution
287	// ============================================================
288	
289	async function checkAndExecuteTask(taskId: string): Promise<void> {
290	  if (!isPrimary) return;
291	
292	  const task = await idbAccessLayer.get<SchedulerTask>('scheduler_tasks', taskId);
293	  if (!task || task.status !== 'active') return;
294	
295	  const nextRun = readNextRunAt(taskId) || task.next_run_at;
296	  if (nextRun > Date.now()) return;
297	
298	  await executeTask(task);
299	}
