14	    const roles = getRouteRoles(path);
15	    const session = $authStore;
16	
17	    // Public route (login)
18	    if (roles === 'public') {
19	      // If already logged in, redirect to dashboard
20	      if (session && session.expires_at > Date.now()) {
21	        navigate('/dashboard');
22	      }
