1	import type { DataSyncMessage, AuthSyncMessage, SchedulerSyncMessage, RegistrationSyncMessage, FlagSyncMessage } from '../types';
2	
3	export const CHANNELS = {
4	  DATA_SYNC: 'data-sync',
5	  AUTH_SYNC: 'auth-sync',
6	  SCHEDULER_SYNC: 'scheduler-sync',
7	  REGISTRATION_SYNC: 'registration-sync',
8	  FLAG_SYNC: 'flag-sync',
9	} as const;
10	
11	type ChannelMessageMap = {
12	  'data-sync': DataSyncMessage;
13	  'auth-sync': AuthSyncMessage;
14	  'scheduler-sync': SchedulerSyncMessage;
15	  'registration-sync': RegistrationSyncMessage;
16	  'flag-sync': FlagSyncMessage;
17	};
18	
19	const channels = new Map<string, BroadcastChannel>();
20	let warnedUnsupported = false;
21	
22	function isSupported(): boolean {
23	  return typeof BroadcastChannel !== 'undefined';
24	}
25	
26	function warnOnce(): void {
27	  if (!warnedUnsupported) {
28	    warnedUnsupported = true;
29	    console.warn('BroadcastChannel is not supported in this environment. Cross-tab communication is disabled.');
30	  }
31	}
32	
33	function getOrCreateChannel(name: string): BroadcastChannel {
34	  let channel = channels.get(name);
35	  if (!channel) {
36	    channel = new BroadcastChannel(name);
37	    channels.set(name, channel);
38	  }
39	  return channel;
40	}
41	
42	function broadcast<K extends keyof ChannelMessageMap>(channelName: K, message: ChannelMessageMap[K]): void {
43	  if (!isSupported()) {
44	    warnOnce();
45	    return;
46	  }
47	  const channel = getOrCreateChannel(channelName);
48	  channel.postMessage(message);
49	}
50	
51	function onMessage<K extends keyof ChannelMessageMap>(
52	  channelName: K,
53	  handler: (message: ChannelMessageMap[K]) => void,
54	): () => void {
55	  if (!isSupported()) {
56	    warnOnce();
57	    return () => {};
58	  }
59	  const channel = getOrCreateChannel(channelName);
60	  const listener = (event: MessageEvent<ChannelMessageMap[K]>) => {
61	    handler(event.data);
62	  };
63	  channel.addEventListener('message', listener);
64	  return () => {
65	    channel.removeEventListener('message', listener);
66	  };
67	}
68	
69	function closeAll(): void {
70	  for (const channel of channels.values()) {
71	    channel.close();
72	  }
73	  channels.clear();
74	}
75	
76	export const channelManager = { broadcast, onMessage, closeAll };
77	export default channelManager;
