35	// ============================================================
36	// 5. isDndActive
37	// ============================================================
38	
39	function isDndActive(): boolean {
40	  const config = parseDndConfig();
41	  const start = parseTimeString(config.start);
42	  const end = parseTimeString(config.end);
43	  const startMinutes = start.hour * 60 + start.minute;
44	  const endMinutes = end.hour * 60 + end.minute;
45	  const now = currentMinuteOfDay();
46	
47	  if (startMinutes > endMinutes) {
48	    // Overnight window: e.g. 22:00 - 07:00
49	    return now >= startMinutes || now < endMinutes;
50	  } else {
51	    return now >= startMinutes && now < endMinutes;
52	  }
53	}
