229	async function createUser(userData: {
230	  username: string;
231	  password: string;
232	  role: Role;
233	  org_unit: string;
234	}): Promise<User> {
235	  const salt = encryptionService.generateSalt();
236	  const passwordHash = await encryptionService.hashPassword(userData.password, salt);
237	
238	  const user: User = {
239	    user_id: crypto.randomUUID(),
240	    username: userData.username,
241	    password_hash: passwordHash,
242	    salt: salt.buffer as ArrayBuffer,
243	    role: userData.role,
244	    org_unit: userData.org_unit,
245	    failed_attempts: 0,
246	    locked_until: null,
247	    encryption_enabled: false,
248	    encryption_salt: null,
249	    _version: 1,
250	  };
251	
252	  await idbAccessLayer.put('users', user);
253	  return user;
254	}
