104	// ============================================================
105	// Payment Recording
106	// ============================================================
107	
108	async function recordPayment(billId: string, payment: PaymentInput): Promise<Payment> {
109	  rbacService.checkPermission('payment:record');
110	
111	  const bill = await idbAccessLayer.get<Bill>('bills', billId);
112	  if (!bill) {
113	    throw new Error(`Bill not found: ${billId}`);
114	  }
115	
116	  const session = rbacService.getCurrentSession();
117	
118	  const paymentRecord: Payment = {
119	    payment_id: crypto.randomUUID(),
120	    bill_id: billId,
121	    amount: payment.amount,
122	    payment_method: payment.payment_method,
123	    payment_date: payment.payment_date,
124	    recorded_by: session.user_id,
125	    _version: 1,
126	  };
127	
128	  await idbAccessLayer.put('payments', paymentRecord as any);
129	
130	  // Check if bill is fully or partially paid
131	  const allPayments = await idbAccessLayer.getAll<Payment>('payments', 'idx_bill', billId);
132	  const totalPaid = allPayments.reduce((sum, p) => sum + p.amount, 0);
133	
134	  if (totalPaid >= bill.total) {
135	    await idbAccessLayer.put('bills', {
136	      ...bill,
137	      status: 'paid',
138	      _version: bill._version + 1,
139	    } as any);
140	  } else if (totalPaid > 0) {
141	    await idbAccessLayer.put('bills', {
142	      ...bill,
143	      status: 'partial',
144	      _version: bill._version + 1,
145	    } as any);
146	  }
147	
148	  return paymentRecord;
149	}
