173	
174	async function exportReconciliationCSV(period: string): Promise<Blob> {
175	  rbacService.checkPermission('billing:export_csv');
176	
177	  const allBills = await idbAccessLayer.getAll<Bill>('bills');
178	  const periodBills = allBills.filter((b) => b.billing_period === period);
179	
180	  const rows: string[] = [
181	    'Participant ID,Billing Period,Housing Fee,Utility Charge,Waiver Amount,Total,Payments Total,Payment Methods,Status',
182	  ];
183	
184	  for (const bill of periodBills) {
185	    const payments = await idbAccessLayer.getAll<Payment>('payments', 'idx_bill', bill.bill_id);
186	    const paymentsTotal = payments.reduce((sum, p) => sum + p.amount, 0);
187	    const paymentMethods = [...new Set(payments.map((p) => p.payment_method))].join(';');
188	
189	    rows.push(
190	      [
