196	        bill.total,
197	        paymentsTotal,
198	        paymentMethods,
199	        bill.status,
200	      ].join(','),
201	    );
202	  }
203	
204	  const csvString = rows.join('\n');
205	  return new Blob([csvString], { type: 'text/csv' });
