9	// ============================================================
10	// Rate Limiting
11	// ============================================================
12	
13	async function checkRateLimit(userId: string): Promise<void> {
14	  const rateLimitAttempts = ((await opsConfigService.getPolicy('rate_limit_attempts')) as number) || 5;
15	  const rateLimitWindowMs = (((await opsConfigService.getPolicy('rate_limit_window_seconds')) as number) || 10) * 1000;
16	
17	  const windowStart = Math.floor(Date.now() / rateLimitWindowMs) * rateLimitWindowMs;
18	  const counterKey = `rate_limit_${userId}_${windowStart}`;
19	
20	  const existing = await idbAccessLayer.get<any>('idempotency_keys', counterKey);
21	  const currentCount = existing ? (existing.result as number) || 0 : 0;
22	
23	  if (currentCount >= rateLimitAttempts) {
24	    const retryAfter = windowStart + rateLimitWindowMs - Date.now();
25	    throw new RateLimitError(retryAfter, `Rate limit exceeded. Try again in ${Math.ceil(retryAfter / 1000)} seconds.`);
26	  }
27	
28	  // Increment counter
29	  await idbAccessLayer.put('idempotency_keys', {
30	    key_id: counterKey,
31	    status: 'completed',
32	    result: currentCount + 1,
33	    created_at: windowStart,
34	    completed_at: null,
35	  });
36	
37	  // Broadcast rate-limit increment to other tabs
38	  channelManager.broadcast(CHANNELS.REGISTRATION_SYNC, {
39	    type: 'rate-limit-increment',
40	    user_id: userId,
41	    attempt_count: currentCount + 1,
42	    window_start: windowStart,
43	  } as RegistrationSyncMessage);
44	}
