46	// ============================================================
47	// Registration Operations
48	// ============================================================
49	
50	async function add(
51	  participantId: string,
52	  sessionId: string,
53	  idempotencyKey: string,
54	): Promise<Registration> {
55	  // 1. RBAC check
56	  rbacService.checkPermission('registration:manage');
57	
58	  // 2. Idempotency check
59	  const idempCheck = await idempotencyService.checkKey(idempotencyKey);
60	  if (idempCheck.isDuplicate) {
61	    return idempCheck.cachedResult as Registration;
62	  }
63	
64	  // 3. Rate limit check
65	  await checkRateLimit(participantId);
66	
67	  // 4. Blacklist check
68	  const isBlacklisted = await opsConfigService.isBlacklisted('participant', participantId);
69	  if (isBlacklisted) {
70	    throw new Error('Registration denied: participant is restricted.');
71	  }
72	
73	  // 5. Atomic transaction: read session, verify capacity, check uniqueness, decrement, create registration
74	  const registration = await idbAccessLayer.transaction<Registration>(
75	    ['sessions', 'registrations', 'idempotency_keys'],
76	    'readwrite',
77	    async (tx) => {
78	      // Read session
79	      const session = await tx.get<SessionRecord>('sessions', sessionId);
80	      if (!session) throw new Error(`Session ${sessionId} not found`);
81	      if (session.status === 'cancelled') throw new Error('Cannot register for a cancelled session');
82	
83	      // Check capacity
84	      const availableCapacity = session.capacity - session.current_enrollment;
85	      if (availableCapacity <= 0) {
86	        throw new Error('Session is full. No seats available.');
87	      }
88	
89	      // Check one-seat-per-participant (query all registrations for this session)
90	      const allRegs = await tx.getAll<Registration>('registrations', 'idx_session', sessionId);
91	      const existingActive = allRegs.find(
92	        (r) => r.participant_id === participantId && r.status === 'active'
93	      );
94	      if (existingActive) {
95	        throw new Error('You already have an active registration for this session.');
96	      }
97	
98	      // Decrement capacity with version check
99	      const updatedSession = {
100	        ...session,
101	        current_enrollment: session.current_enrollment + 1,
102	        _version: session._version + 1,
103	      };
104	      await tx.put('sessions', updatedSession);
105	
106	      // Create registration
107	      const reg: Registration = {
108	        registration_id: crypto.randomUUID(),
109	        participant_id: participantId,
110	        session_id: sessionId,
111	        status: 'active',
112	        registered_at: Date.now(),
113	        _version: 1,
114	      };
115	      await tx.put('registrations', reg);
116	
117	      return reg;
118	    }
119	  );
120	
121	  // 6. Mark idempotency key as complete
122	  await idempotencyService.markComplete(idempotencyKey, registration);
123	
124	  // 7. Broadcast capacity change
125	  const updatedSession = await idbAccessLayer.get<SessionRecord>('sessions', sessionId);
126	  channelManager.broadcast(CHANNELS.REGISTRATION_SYNC, {
127	    type: 'capacity-changed',
128	    session_id: sessionId,
129	    new_capacity: updatedSession ? updatedSession.capacity - updatedSession.current_enrollment : 0,
130	    version: updatedSession?._version,
131	  } as RegistrationSyncMessage);
132	
133	  return registration;
134	}
