136	async function drop(
137	  participantId: string,
138	  sessionId: string,
139	  idempotencyKey: string,
140	): Promise<void> {
141	  // 1. RBAC
142	  rbacService.checkPermission('registration:manage');
143	
144	  // 2. Idempotency
145	  const idempCheck = await idempotencyService.checkKey(idempotencyKey);
146	  if (idempCheck.isDuplicate) return;
147	
148	  // 3. Rate limit
149	  await checkRateLimit(participantId);
150	
151	  // 4. Atomic transaction
152	  await idbAccessLayer.transaction<void>(
153	    ['sessions', 'registrations'],
154	    'readwrite',
155	    async (tx) => {
156	      // Find the active registration
157	      const allRegs = await tx.getAll<Registration>('registrations', 'idx_session', sessionId);
158	      const activeReg = allRegs.find(
159	        (r) => r.participant_id === participantId && r.status === 'active'
160	      );
161	      if (!activeReg) {
162	        throw new Error('No active registration found for this session.');
163	      }
164	
165	      // Mark registration as cancelled
166	      await tx.put('registrations', {
167	        ...activeReg,
168	        status: 'cancelled',
169	        _version: activeReg._version + 1,
170	      });
171	
172	      // Increment session capacity
173	      const session = await tx.get<SessionRecord>('sessions', sessionId);
174	      if (!session) throw new Error(`Session ${sessionId} not found`);
175	
176	      await tx.put('sessions', {
177	        ...session,
178	        current_enrollment: Math.max(0, session.current_enrollment - 1),
179	        _version: session._version + 1,
180	      });
181	    }
182	  );
183	
184	  // Mark idempotency complete
185	  await idempotencyService.markComplete(idempotencyKey, { dropped: true });
186	
187	  // Broadcast
188	  const updatedSession = await idbAccessLayer.get<SessionRecord>('sessions', sessionId);
189	  channelManager.broadcast(CHANNELS.REGISTRATION_SYNC, {
190	    type: 'capacity-changed',
191	    session_id: sessionId,
192	    new_capacity: updatedSession ? updatedSession.capacity - updatedSession.current_enrollment : 0,
193	    version: updatedSession?._version,
194	  } as RegistrationSyncMessage);
195	}
