1	import { idbAccessLayer } from './idbAccessLayer';
2	import { rbacService } from './rbacService';
3	import { opsConfigService } from './opsConfigService';
4	import type { Booking, BookingRequest, Conflict, ConflictResult, ScoredRoom, Room, MaintenanceWindow, Equipment } from '../types';
5	import { AccessError, VersionConflictError } from '../types';
6	
7	// ============================================================
8	// Helpers
9	// ============================================================
10	
11	function extractDigits(code: string): number {
12	  const match = code.match(/\d+/);
13	  return match ? parseInt(match[0], 10) : 0;
14	}
15	
16	function timeOverlaps(aStart: number, aEnd: number, bStart: number, bEnd: number): boolean {
17	  return aStart < bEnd && aEnd > bStart;
18	}
19	
20	// ============================================================
21	// detectConflicts
22	// ============================================================
23	
24	async function detectConflicts(request: BookingRequest): Promise<Conflict[]> {
25	  const conflicts: Conflict[] = [];
26	
27	  // (a) Time overlap with existing bookings in the same room
28	  const allBookings = await idbAccessLayer.getAll<Booking>('bookings');
29	  const overlapping = allBookings.filter(
30	    (b) =>
31	      b.room_id === request.room_id &&
32	      b.status !== 'cancelled' &&
33	      b.start_time < request.end_time &&
34	      b.end_time > request.start_time,
35	  );
36	  for (const b of overlapping) {
37	    conflicts.push({
38	      type: 'time_overlap',
39	      description: `Booking ${b.booking_id} overlaps with the requested time range`,
40	      conflicting_record_id: b.booking_id,
41	    });
42	  }
43	
44	  // (b) Maintenance windows
45	  const windows = await opsConfigService.getMaintenanceWindows(request.room_id);
46	  const overlappingWindows = windows.filter((w: MaintenanceWindow) =>
47	    timeOverlaps(request.start_time, request.end_time, w.start_time, w.end_time),
48	  );
49	  for (const w of overlappingWindows) {
50	    conflicts.push({
51	      type: 'maintenance',
52	      description: `Maintenance window "${w.description}" overlaps with the requested time range`,
53	      conflicting_record_id: w.window_id,
54	    });
55	  }
56	
57	  // (c) Equipment exclusivity
58	  for (const eqType of request.requested_equipment) {
59	    const equipmentItems = await idbAccessLayer.getAll<Equipment>('equipment', 'idx_type', eqType);
60	    const exclusiveItems = equipmentItems.filter((e) => e.is_exclusive);
61	
62	    for (const item of exclusiveItems) {
63	      // Check if this exclusive equipment item is reserved by another booking in the time range
64	      const conflictingBookings = allBookings.filter(
65	        (b) =>
66	          b.status !== 'cancelled' &&
67	          b.requested_equipment.includes(eqType) &&
68	          b.start_time < request.end_time &&
69	          b.end_time > request.start_time,
70	      );
71	      for (const cb of conflictingBookings) {
72	        conflicts.push({
73	          type: 'equipment',
74	          description: `Exclusive equipment "${item.name}" (${eqType}) is reserved by booking ${cb.booking_id}`,
75	          conflicting_record_id: cb.booking_id,
76	        });
77	      }
78	    }
79	  }
80	
81	  return conflicts;
82	}
83	
84	// ============================================================
85	// getAlternatives
86	// ============================================================
87	
88	async function getAlternatives(request: BookingRequest): Promise<ScoredRoom[]> {
89	  const allRooms = await idbAccessLayer.getAll<Room>('rooms');
90	
91	  // Filter candidates by capacity proximity
92	  const candidates = allRooms.filter(
93	    (room) => Math.abs(room.capacity - request.participant_capacity) <= 10,
94	  );
95	
96	  if (candidates.length === 0) return [];
97	
98	  // Pre-fetch data for scoring
99	  const allBookings = await idbAccessLayer.getAll<Booking>('bookings');
100	
101	  // Compute MAX_DISTANCE dynamically across all candidate rooms
102	  let maxDistance = 0;
103	  for (let i = 0; i < candidates.length; i++) {
104	    for (let j = i + 1; j < candidates.length; j++) {
105	      const b1 = extractDigits(candidates[i].building_code);
106	      const f1 = extractDigits(candidates[i].floor_code);
107	      const b2 = extractDigits(candidates[j].building_code);
108	      const f2 = extractDigits(candidates[j].floor_code);
109	      const dist = Math.abs(b1 - b2) + Math.abs(f1 - f2);
110	      if (dist > maxDistance) maxDistance = dist;
111	    }
112	  }
113	
114	  // Parse the request room's building/floor for distance calculation
115	  const requestRoom = allRooms.find((r) => r.room_id === request.room_id);
116	  const reqBuilding = requestRoom ? extractDigits(requestRoom.building_code) : 0;
117	  const reqFloor = requestRoom ? extractDigits(requestRoom.floor_code) : 0;
118	
119	  const scored: ScoredRoom[] = [];
120	
121	  for (const room of candidates) {
122	    // Capacity fit (40%)
123	    const capacityFit = Math.max(
124	      0,
125	      Math.min(1, 1 - Math.abs(room.capacity - request.participant_capacity) / request.participant_capacity),
126	    );
127	
128	    // Equipment match (30%)
129	    let equipmentMatch: number;
130	    if (request.requested_equipment.length === 0) {
131	      equipmentMatch = 1;
132	    } else {
133	      const matchCount = request.requested_equipment.filter((eq) =>
134	        room.equipment.includes(eq),
135	      ).length;
136	      equipmentMatch = matchCount / request.requested_equipment.length;
137	    }
138	
139	    // Availability (20%)
140	    const hasOverlappingBooking = allBookings.some(
141	      (b) =>
142	        b.room_id === room.room_id &&
143	        b.status !== 'cancelled' &&
144	        timeOverlaps(request.start_time, request.end_time, b.start_time, b.end_time),
145	    );
146	    const maintenanceWindows = await opsConfigService.getMaintenanceWindows(room.room_id);
147	    const hasOverlappingMaintenance = maintenanceWindows.some((w: MaintenanceWindow) =>
148	      timeOverlaps(request.start_time, request.end_time, w.start_time, w.end_time),
149	    );
150	    const availability = hasOverlappingBooking || hasOverlappingMaintenance ? 0.0 : 1.0;
151	
152	    // Distance (10%)
153	    const roomBuilding = extractDigits(room.building_code);
154	    const roomFloor = extractDigits(room.floor_code);
155	    const distance = Math.abs(reqBuilding - roomBuilding) + Math.abs(reqFloor - roomFloor);
156	    const distanceScore = maxDistance === 0 ? 1 : 1 - distance / maxDistance;
157	
158	    const totalScore =
159	      capacityFit * 0.4 +
160	      equipmentMatch * 0.3 +
161	      availability * 0.2 +
162	      distanceScore * 0.1;
163	
164	    scored.push({
165	      room,
166	      total_score: totalScore,
167	      scores: {
168	        capacity_fit: capacityFit,
169	        equipment_match: equipmentMatch,
170	        availability,
171	        distance: distanceScore,
172	      },
173	    });
174	  }
175	
176	  // Sort descending by total_score, return top 5
177	  scored.sort((a, b) => b.total_score - a.total_score);
178	  return scored.slice(0, 5);
179	}
