181	// ============================================================
182	// createBooking
183	// ============================================================
184	
185	async function createBooking(request: BookingRequest): Promise<Booking | ConflictResult> {
186	  // 1. RBAC check
187	  rbacService.checkPermission('booking:create');
188	
189	  // 2. Policy checks
190	  const windowDaysRaw = await opsConfigService.getPolicy('booking_window_days');
191	  const windowDays = typeof windowDaysRaw === 'number' ? windowDaysRaw : 14;
192	  if (request.start_time > Date.now() + windowDays * 86400000) {
193	    throw new Error(`Booking too far in advance. Maximum booking window is ${windowDays} days.`);
194	  }
195	
196	  const maxActiveRaw = await opsConfigService.getPolicy('max_active_reservations');
197	  const maxActive = typeof maxActiveRaw === 'number' ? maxActiveRaw : 3;
198	  const allBookings = await idbAccessLayer.getAll<Booking>('bookings');
199	  const activeCount = allBookings.filter(
200	    (b) => b.user_id === request.user_id && b.status !== 'cancelled',
201	  ).length;
202	  if (activeCount >= maxActive) {
203	    throw new Error(`Maximum active reservations (${maxActive}) reached.`);
204	  }
205	
206	  // 3. Blacklist checks
207	  const roomBlacklisted = await opsConfigService.isBlacklisted('room', request.room_id);
208	  if (roomBlacklisted) {
209	    throw new Error(`Room ${request.room_id} is blacklisted.`);
210	  }
211	  const participantBlacklisted = await opsConfigService.isBlacklisted('participant', request.user_id);
212	  if (participantBlacklisted) {
213	    throw new Error(`User ${request.user_id} is blacklisted.`);
214	  }
215	
216	  // 4. Conflict detection
217	  const conflicts = await detectConflicts(request);
218	  if (conflicts.length > 0) {
219	    const alternatives = await getAlternatives(request);
220	    return { conflicts, alternatives } as ConflictResult;
221	  }
222	
223	  // 5. Create booking
224	  const booking: Booking = {
225	    booking_id: crypto.randomUUID(),
226	    room_id: request.room_id,
227	    user_id: request.user_id,
228	    start_time: request.start_time,
229	    end_time: request.end_time,
230	    requested_equipment: request.requested_equipment,
231	    participant_capacity: request.participant_capacity,
232	    status: 'confirmed',
233	    created_at: Date.now(),
234	    _version: 1,
235	  };
236	
237	  await idbAccessLayer.put('bookings', booking);
238	  return booking;
239	}
