241	// ============================================================
242	// updateBooking
243	// ============================================================
244	
245	async function updateBooking(bookingId: string, updates: Partial<Booking>): Promise<Booking> {
246	  const existing = await idbAccessLayer.get<Booking>('bookings', bookingId);
247	  if (!existing) {
248	    throw new Error(`Booking ${bookingId} not found.`);
249	  }
250	
251	  // RBAC: check edit_own (with ownership) or admin
252	  const session = rbacService.getCurrentSession();
253	  try {
254	    rbacService.checkPermission('booking:edit_own');
255	    rbacService.checkOwnership(existing.user_id, session.user_id);
256	  } catch {
257	    // If ownership check fails, must be admin
258	    rbacService.checkPermission('booking:cancel_any');
259	  }
260	
261	  // Merge updates with optimistic locking
262	  const updated: Booking = {
263	    ...existing,
264	    ...updates,
265	    booking_id: existing.booking_id, // prevent overwriting key fields
266	    _version: existing._version + 1,
267	  };
268	
269	  await idbAccessLayer.put('bookings', updated);
270	  return updated;
271	}
