277	async function cancelBooking(bookingId: string): Promise<void> {
278	  const existing = await idbAccessLayer.get<Booking>('bookings', bookingId);
279	  if (!existing) {
280	    throw new Error(`Booking ${bookingId} not found.`);
281	  }
282	
283	  // RBAC: cancel_own (if owner) or cancel_any
284	  const session = rbacService.getCurrentSession();
285	  try {
286	    rbacService.checkPermission('booking:cancel_own');
287	    rbacService.checkOwnership(existing.user_id, session.user_id);
288	  } catch {
289	    rbacService.checkPermission('booking:cancel_any');
290	  }
291	
292	  const cancelled: Booking = {
293	    ...existing,
294	    status: 'cancelled',
295	    _version: existing._version + 1,
296	  };
297	
298	  await idbAccessLayer.put('bookings', cancelled);
299	}
