1	import { idbAccessLayer } from './idbAccessLayer';
2	import type { IdempotencyKey } from '../types';
3	import { ConcurrencyError } from '../types';
4	
5	const STORE = 'idempotency_keys';
6	const IN_PROGRESS_TIMEOUT = 5 * 60 * 1000; // 5 minutes
7	const COMPLETED_TTL = 24 * 60 * 60 * 1000; // 24 hours
8	
9	async function checkKey(key: string): Promise<{ isDuplicate: boolean; cachedResult?: unknown }> {
10	  const record = await idbAccessLayer.get(STORE, key) as IdempotencyKey | undefined;
11	
12	  if (record) {
13	    if (record.status === 'completed') {
14	      return { isDuplicate: true, cachedResult: record.result };
15	    }
16	
17	    if (record.status === 'in-progress') {
18	      if (Date.now() - record.created_at < IN_PROGRESS_TIMEOUT) {
19	        throw new ConcurrencyError('Operation is already in progress in another tab');
20	      }
21	
22	      // Abandoned in-progress record — reclaim it
23	      const updated: IdempotencyKey = {
24	        ...record,
25	        created_at: Date.now(),
26	      };
27	      await idbAccessLayer.put(STORE, updated);
28	      return { isDuplicate: false };
29	    }
30	  }
31	
32	  // Not found — create new in-progress record
33	  const newRecord: IdempotencyKey = {
34	    key_id: key,
35	    status: 'in-progress',
36	    result: null,
37	    created_at: Date.now(),
38	    completed_at: null,
39	  };
40	  await idbAccessLayer.put(STORE, newRecord);
41	  return { isDuplicate: false };
42	}
43	
44	async function markComplete(key: string, result: unknown): Promise<void> {
45	  const record = await idbAccessLayer.get(STORE, key) as IdempotencyKey | undefined;
46	
47	  if (record) {
48	    const updated: IdempotencyKey = {
49	      ...record,
50	      status: 'completed',
51	      result,
52	      completed_at: Date.now(),
53	    };
54	    await idbAccessLayer.put(STORE, updated);
55	  }
56	}
57	
58	async function cleanup(): Promise<void> {
59	  const records = await idbAccessLayer.getAll(STORE) as IdempotencyKey[];
60	  const now = Date.now();
61	
62	  for (const record of records) {
63	    if (record.status === 'completed' && now - record.created_at > COMPLETED_TTL) {
64	      await idbAccessLayer.delete(STORE, record.key_id);
65	    }
66	  }
67	}
68	
69	export const idempotencyService = { checkKey, markComplete, cleanup };
70	export default idempotencyService;
