17	function matchesTargeting(message: Message, role: Role, orgUnit: string): boolean {
18	  // target_org_scope 'all' means everyone
19	  if (message.target_org_scope === 'all') {
20	    // Still check target_roles if specified
21	    if (message.target_roles.length > 0 && !message.target_roles.includes(role)) {
22	      return false;
23	    }
24	    return true;
25	  }
26	
27	  // Check role targeting: empty means all roles
28	  if (message.target_roles.length > 0 && !message.target_roles.includes(role)) {
29	    return false;
30	  }
31	
32	  // Check org_unit targeting: empty means all org units
33	  if (message.target_org_units.length > 0 && !message.target_org_units.includes(orgUnit)) {
34	    return false;
35	  }
36	
37	  return true;
38	}
