      expect(rbacService.isPermitted('PARTICIPANT', 'user:create')).toBe(false);
    });

    it('returns false for unknown operation', () => {
      expect(rbacService.isPermitted('SYSTEM_ADMIN', 'fake:op')).toBe(false);
    });
  });

